export type LiquidLensOptions = {
  borderRadius?: number;
  scale?: number;
  depth?: number;
  curvature?: number;
  splay?: number;
  chroma?: number;
  blur?: number;
  glow?: number;
  edgeHighlight?: number;
  specularAngle?: number;
};

export const liquidLensPresets = {
