.liquid-switch[data-interacting] .liquid-switch__refraction, .liquid-switch[data-interacting] .liquid-switch__lens, .liquid-switch[data-interacting] .liquid-switch__rim, .liquid-switch[data-interacting] .liquid-switch__light { opacity: 1; }
