.liquid-slider { width: min(320px, 100%); height: calc(var(--slider-height) + 16px); display: flex; align-items: center; position: relative; touch-action: none; contain: layout style; cursor: pointer; }
.liquid-slider[data-orientation="vertical"] { width: calc(var(--slider-height) + 16px); height: 240px; flex-direction: column; }
.liquid-slider__track { position: relative; flex: 1; height: var(--slider-track-height); margin-inline: calc(var(--slider-thumb-width) / 2); border-radius: 999px; overflow: visible; background: rgba(120,120,128,.2); box-shadow: inset 0 1px 2px rgba(0,0,0,.1), 0 .5px 0 rgba(255,255,255,.55); }
.liquid-slider[data-orientation="vertical"] .liquid-slider__track { width: var(--slider-track-height); height: 100%; margin-inline: 0; margin-block: calc(var(--slider-thumb-width) / 2); }
.liquid-slider__fill { position: absolute; height: 100%; border-radius: inherit; background: var(--slider-tint); box-shadow: 2px 0 0 var(--slider-tint); }
.liquid-slider[data-orientation="vertical"] .liquid-slider__fill { width: 100%; height: auto; box-shadow: 0 -2px 0 var(--slider-tint); }
.liquid-slider__thumb { display: block; width: var(--slider-thumb-width); height: calc(var(--slider-height) - 4px); border: 0; border-radius: 999px; background: #fff; box-shadow: 0 2px 6px rgba(0,0,0,.2), 0 .5px 1px rgba(0,0,0,.1); transition: width .42s var(--liquid-spring), height .42s var(--liquid-spring), background .26s ease, box-shadow .34s ease, transform .48s var(--liquid-spring); overflow: hidden; cursor: grab; will-change: transform, width, height; }
.liquid-slider__thumb:focus-visible { outline: 4px solid rgba(0,122,255,.28); outline-offset: 3px; }
.liquid-slider__occlusion, .liquid-slider__refraction, .liquid-slider__lens, .liquid-slider__rim, .liquid-slider__light { position: absolute; inset: 0; border-radius: inherit; opacity: 0; transition: opacity .22s ease; }
.liquid-slider__occlusion { z-index: 0; background: rgba(245,245,247,.62); backdrop-filter: blur(12px) saturate(1.2); -webkit-backdrop-filter: blur(12px) saturate(1.2); box-shadow: inset 0 0 12px rgba(255,255,255,.35); transition: opacity .2s ease-out; }
.liquid-slider__refraction { z-index: 1; background: linear-gradient(to right, var(--slider-tint) 0 42%, color-mix(in srgb, var(--slider-tint), white 10%) 47%, color-mix(in srgb, var(--slider-tint), rgba(120,120,128,.24) 50%) 50%, rgba(120,120,128,.24) 56% 100%) center / 125% calc(var(--slider-track-height) * 1.35) no-repeat; box-shadow: inset 0 1px 2px rgba(255,255,255,.24), inset 0 -1px 2px rgba(0,0,0,.05); transform: scaleX(1.04) scaleY(1.02); transform-origin: center; transition: opacity .26s ease-out, transform .34s var(--liquid-ease-out); will-change: transform, opacity; }
.liquid-slider__lens { z-index: 2; background: radial-gradient(ellipse at var(--liquid-light-x) 45%, rgba(255,255,255,.18), transparent 48%), rgba(255,255,255,.12); backdrop-filter: blur(1px) saturate(2.15) brightness(1.2); -webkit-backdrop-filter: blur(1px) saturate(2.15) brightness(1.2); box-shadow: inset 2px 0 2px rgba(85,205,255,.12), inset -2px 0 2px rgba(255,100,135,.1); }
.liquid-slider__rim { z-index: 3; inset: .5px; border: .5px solid rgba(255,255,255,.78); box-shadow: inset 1px 1px 2px rgba(255,255,255,.95), inset -1px -1px 2px rgba(0,0,0,.12); }
.liquid-slider__light { z-index: 4; inset: -25%; background: radial-gradient(circle at var(--liquid-light-x) 38%, white, rgba(255,255,255,.42) 20%, transparent 52%); }
.liquid-slider[data-interacting] .liquid-slider__thumb { width: calc(var(--slider-thumb-width) + 10px + var(--liquid-stretch)); height: calc(var(--slider-height) + 8px); background: rgba(255,255,255,.18); box-shadow: 0 7px 16px rgba(0,0,0,.22), inset 0 0 7px rgba(255,255,255,.9), 0 0 0 .5px rgba(255,255,255,.7); transform: translateX(var(--liquid-offset)) scaleY(var(--liquid-squash)) skewX(var(--liquid-skew)); transition: width .34s var(--liquid-spring), height .34s var(--liquid-spring), background .22s ease, box-shadow .28s ease, transform .36s var(--liquid-spring); }
.liquid-slider[data-interacting] .liquid-slider__occlusion, .liquid-slider[data-interacting] .liquid-slider__refraction, .liquid-slider[data-interacting] .liquid-slider__lens, .liquid-slider[data-interacting] .liquid-slider__rim, .liquid-slider[data-interacting] .liquid-slider__light { opacity: 1; }
.liquid-slider[data-interacting] .liquid-slider__refraction { transform: scaleX(1.08) scaleY(1.04); }
.liquid-slider[data-dragging] .liquid-slider__thumb { transition: width .12s var(--liquid-follow), height .12s var(--liquid-follow), background .12s ease-out, box-shadow .14s ease-out, transform .075s var(--liquid-follow); cursor: grabbing; }
.liquid-slider[data-dragging] .liquid-slider__refraction { transform: scaleX(1.12) scaleY(1.06); transition: opacity .16s ease-out, transform .16s var(--liquid-follow); }
