/* Tabs */
.liquid-tabs { width: 100%; }
.liquid-tabs__list { --tabs-indicator-x: 4px; --tabs-indicator-width: 0px; --tabs-indicator-height: 36px; --tabs-tint: rgba(255,255,255,.72); --tabs-active-tint: rgba(255,255,255,.2); --tabs-label: rgba(60,60,67,.72); --tabs-label-active: #111113; display: inline-flex; align-items: center; gap: 2px; min-width: min(100%, 360px); padding: 4px; position: relative; isolation: isolate; border: .5px solid rgba(255,255,255,.52); border-radius: 999px; background: rgba(118,118,128,.14); box-shadow: inset 0 1px 2px rgba(0,0,0,.08), 0 1px 0 rgba(255,255,255,.4); color: #1c1c1e; touch-action: manipulation; user-select: none; }
.liquid-tabs__list--small { --tabs-indicator-height: 30px; }
.liquid-tabs__list--large { --tabs-indicator-height: 42px; }
.liquid-tabs__indicator { width: var(--tabs-indicator-width); height: var(--tabs-indicator-height); position: absolute; z-index: 0; left: 0; top: 50%; overflow: hidden; border-radius: 999px; pointer-events: none; opacity: 0; background: var(--tabs-tint); box-shadow: 0 2px 6px rgba(0,0,0,.16), 0 .5px 1px rgba(0,0,0,.08); transform: translate3d(var(--tabs-indicator-x),-50%,0); transform-origin: center; transition: width .62s var(--liquid-tabs-spring), height .5s var(--liquid-tabs-spring), transform .7s var(--liquid-tabs-follow), background .32s ease, box-shadow .4s ease, opacity .12s ease; will-change: width, height, transform; }
.liquid-tabs__list[data-indicator-ready] .liquid-tabs__indicator { opacity: 1; }
.liquid-tabs__refraction, .liquid-tabs__indicator-lens, .liquid-tabs__indicator-rim, .liquid-tabs__indicator-light { position: absolute; inset: 0; border-radius: inherit; pointer-events: none; }
.liquid-tabs__refraction { z-index: 0; opacity: .28; background: linear-gradient(90deg,color-mix(in srgb,var(--tabs-tint),transparent 18%) 0 34%,rgba(255,255,255,.74) 47% 53%,color-mix(in srgb,var(--tabs-tint),transparent 18%) 66% 100%) center / 116% 64% no-repeat; transform: scaleX(1.04); transition: opacity .25s ease, transform .5s var(--liquid-tabs-spring); }
.liquid-tabs__indicator-lens { z-index: 1; background: rgba(255,255,255,.16); backdrop-filter: blur(2.5px) saturate(1.8) brightness(1.09); -webkit-backdrop-filter: blur(2.5px) saturate(1.8) brightness(1.09); }
.liquid-tabs__indicator-rim { z-index: 2; inset: .5px; border: .5px solid rgba(255,255,255,.68); box-shadow: inset 1px 1px 1.5px rgba(255,255,255,.8), inset -1px -1px 1.5px rgba(0,0,0,.1); }
.liquid-tabs__indicator-light { z-index: 3; inset: -30%; opacity: 0; background: radial-gradient(circle at var(--liquid-light-x) 38%, rgba(255,255,255,.96), rgba(255,255,255,.28) 22%, transparent 52%); transition: opacity .2s ease; }
.liquid-tabs__list[data-interacting] .liquid-tabs__indicator { width: calc(var(--tabs-indicator-width) + 8px + var(--liquid-stretch)); height: calc(var(--tabs-indicator-height) + 8px); background: var(--tabs-active-tint); box-shadow: 0 7px 16px rgba(0,0,0,.22), inset 0 0 7px rgba(255,255,255,.72), 0 0 0 .5px rgba(255,255,255,.62); transform: translate3d(calc(var(--tabs-indicator-x) - 4px + var(--liquid-offset)),-50%,0) scaleY(var(--liquid-squash)) skewX(var(--liquid-skew)); }
.liquid-tabs__list[data-interacting] .liquid-tabs__indicator-light { opacity: 1; }
.liquid-tabs__list[data-interacting] .liquid-tabs__refraction { opacity: .76; transform: scaleX(1.1) scaleY(1.04); }
.liquid-tabs__list[data-dragging] .liquid-tabs__indicator { transition: width .46s var(--liquid-tabs-spring), height .4s var(--liquid-tabs-spring), transform .5s var(--liquid-tabs-follow), background .3s ease-out, box-shadow .3s ease-out; }
.liquid-tabs__trigger { min-width: 0; height: var(--tabs-indicator-height); flex: 1 1 0; padding: 0 18px; position: relative; z-index: 1; display: inline-flex; align-items: center; justify-content: center; gap: 7px; border: 0; border-radius: 999px; background: transparent; color: var(--tabs-label); font-size: 13px; font-weight: 560; letter-spacing: -.01em; white-space: nowrap; cursor: pointer; transition: color .2s ease, transform .2s var(--liquid-ease-out); }
.liquid-tabs__list--small .liquid-tabs__trigger { padding-inline: 14px; font-size: 12px; }
.liquid-tabs__list--large .liquid-tabs__trigger { padding-inline: 22px; font-size: 14px; }
.liquid-tabs__trigger[data-state="active"] { color: var(--tabs-label-active); }
.liquid-tabs__trigger:focus-visible { outline: 3px solid rgba(0,122,255,.3); outline-offset: 2px; }
.liquid-tabs__trigger:disabled { opacity: .4; cursor: default; }
.liquid-tabs__content { margin-top: 18px; outline: none; }
.liquid-tabs__content:focus-visible { outline: 3px solid rgba(0,122,255,.28); outline-offset: 4px; border-radius: 12px; }

:is(.dark, [data-theme="dark"]) .liquid-tabs__list { --tabs-tint: rgba(118,118,128,.58); --tabs-active-tint: rgba(118,118,128,.34); --tabs-label: rgba(235,235,245,.66); --tabs-label-active: #fff; border-color: rgba(255,255,255,.16); background: rgba(235,235,245,.1); box-shadow: inset 0 1px 2px rgba(0,0,0,.32), 0 1px 0 rgba(255,255,255,.08); color: #f5f5f7; }
:is(.dark, [data-theme="dark"]) .liquid-tabs__indicator { box-shadow: 0 3px 9px rgba(0,0,0,.42), 0 .5px 0 rgba(255,255,255,.14); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__indicator-lens { background: rgba(255,255,255,.07); backdrop-filter: blur(2.5px) saturate(1.6) brightness(1.02); -webkit-backdrop-filter: blur(2.5px) saturate(1.6) brightness(1.02); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__refraction { background-image: linear-gradient(90deg,rgba(118,118,128,.34) 0 34%,rgba(255,255,255,.26) 47% 53%,rgba(118,118,128,.34) 66% 100%); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__indicator-rim { border-color: rgba(255,255,255,.2); box-shadow: inset 1px 1px 1.5px rgba(255,255,255,.22), inset -1px -1px 1.5px rgba(0,0,0,.42); }
:is(.dark, [data-theme="dark"]) .liquid-tabs__list[data-interacting] .liquid-tabs__indicator { box-shadow: 0 9px 22px rgba(0,0,0,.46), inset 0 0 9px rgba(255,255,255,.2), 0 0 0 .5px rgba(255,255,255,.2); }

/* Video player */
.liquid-video { width: 100%; aspect-ratio: 16 / 9; position: relative; isolation: isolate; overflow: hidden; border-radius: 28px; background: #09090b; color: #fff; box-shadow: 0 24px 70px rgba(0,0,0,.24); outline: none; }
.liquid-video:focus-visible { outline: 3px solid rgba(255,255,255,.72); outline-offset: 4px; }
.liquid-video__media, .liquid-video__canvas { width: 100%; height: 100%; position: absolute; inset: 0; object-fit: cover; transition: opacity .2s ease; }
.liquid-video__media { z-index: 0; }
.liquid-video__canvas { z-index: 1; opacity: 0; pointer-events: none; }
.liquid-video[data-renderer-ready] .liquid-video__media { opacity: 0; }
.liquid-video[data-renderer-ready] .liquid-video__canvas { opacity: 1; }
.liquid-video__center-play { width: 64px; height: 58px; padding: 0; position: absolute; z-index: 3; left: 50%; top: 50%; display: grid; place-items: center; border: .5px solid rgba(255,255,255,.48); border-radius: 999px; background: rgba(255,255,255,.2); color: #fff; box-shadow: 0 9px 24px rgba(0,0,0,.28), inset 1px 1px 1.5px rgba(255,255,255,.62), inset -1px -1px 1.5px rgba(0,0,0,.18); backdrop-filter: blur(2px) saturate(1.7); -webkit-backdrop-filter: blur(2px) saturate(1.7); transform: translate(-50%,-50%) scale(.86); opacity: 0; pointer-events: none; cursor: pointer; transition: width .42s var(--liquid-spring), height .42s var(--liquid-spring), transform .42s var(--liquid-spring), opacity .2s ease; }
.liquid-video[data-paused] .liquid-video__center-play { opacity: 1; pointer-events: auto; transform: translate(-50%,-50%) scale(1); }
.liquid-video__center-play:active { width: 72px; height: 66px; }
.liquid-video__center-play:focus-visible, .liquid-video__button:focus-visible { outline: 2px solid rgba(255,255,255,.9); outline-offset: 2px; }
.liquid-video__controls { min-height: 58px; padding: 8px; position: absolute; z-index: 4; left: 16px; right: 16px; bottom: 16px; display: flex; align-items: center; gap: 7px; border: .5px solid rgba(255,255,255,.24); border-radius: 20px; background: rgba(18,18,20,.3); box-shadow: 0 12px 32px rgba(0,0,0,.25), inset 0 1px 1px rgba(255,255,255,.14); backdrop-filter: blur(18px) saturate(1.35); -webkit-backdrop-filter: blur(18px) saturate(1.35); opacity: 0; transform: translateY(12px); pointer-events: none; transition: opacity .28s ease, transform .4s var(--liquid-ease-out); }
.liquid-video[data-controls-visible] .liquid-video__controls { opacity: 1; transform: translateY(0); pointer-events: auto; }
.liquid-video__button { width: 40px; height: 40px; flex: 0 0 auto; padding: 0; display: grid; place-items: center; border: .5px solid rgba(255,255,255,.3); border-radius: 999px; background: rgba(255,255,255,.14); color: #fff; box-shadow: 0 4px 11px rgba(0,0,0,.18), inset 1px 1px 1px rgba(255,255,255,.32); cursor: pointer; transition: width .34s var(--liquid-spring), height .34s var(--liquid-spring), transform .34s var(--liquid-spring), background .2s ease; }
.liquid-video__button:active { width: 46px; height: 44px; transform: scaleY(.96); background: rgba(255,255,255,.22); }
.liquid-video__time { min-width: 67px; color: rgba(255,255,255,.82); font-size: 10px; font-variant-numeric: tabular-nums; text-align: center; }
.liquid-video__time i { color: rgba(255,255,255,.38); font-style: normal; }
.liquid-video__scrubber { height: 42px; flex: 1; min-width: 100px; padding-inline: 6px; display: flex; align-items: center; overflow: visible; }
.liquid-video__scrubber .liquid-slider { width: 100%; flex: 1; }
.liquid-video__scrubber .liquid-slider__track { background: rgba(255,255,255,.24); }
.liquid-video__scrubber .liquid-slider__thumb { background: rgba(255,255,255,.86); box-shadow: 0 4px 10px rgba(0,0,0,.25), inset 1px 1px 1px rgba(255,255,255,.55); }

@media (max-width: 640px) {
  .liquid-video { border-radius: 20px; }
  .liquid-video__controls { left: 8px; right: 8px; bottom: 8px; min-height: 52px; padding: 6px; gap: 5px; }
  .liquid-video__button { width: 36px; height: 36px; }
  .liquid-video__time, .liquid-video__button:nth-of-type(2), .liquid-video__button:nth-of-type(3) { display: none; }
}

@media (prefers-reduced-motion: reduce) {
  .liquid-switch *, .liquid-slider *, .liquid-tabs *, .liquid-video * { transition-duration: .01ms !important; animation-duration: .01ms !important; }
}

@media (prefers-reduced-transparency: reduce) {
  .liquid-switch__refraction, .liquid-slider__refraction, .liquid-tabs__refraction { filter: none !important; opacity: 0 !important; }
  .liquid-switch__lens, .liquid-slider__lens, .liquid-tabs__indicator-lens { backdrop-filter: none; -webkit-backdrop-filter: none; background: rgba(245,245,247,.92); }
  :is(.dark, [data-theme="dark"]) .liquid-tabs__indicator-lens { background: rgba(72,72,78,.94); }
  .liquid-video__controls, .liquid-video__button, .liquid-video__center-play { backdrop-filter: none; -webkit-backdrop-filter: none; background: rgba(28,28,30,.94); }
}
